import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { ToastContainer, toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

const API_URL = 'http://localhost:5000/api';

const genres = [
  'Action', 'Adventure', 'Animation', 'Comedy', 'Crime',
  'Documentary', 'Drama', 'Family', 'Fantasy', 'Horror',
  'Musical', 'Mystery', 'Romance', 'Sci-Fi', 'Thriller',
  'War', 'Western'
];

// Styles
const styles = {
  container: {
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '20px',
  },
  navbar: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '20px 40px',
    background: 'rgba(26, 26, 46, 0.95)',
    backdropFilter: 'blur(10px)',
    position: 'sticky',
    top: 0,
    zIndex: 100,
    borderBottom: '1px solid rgba(233, 69, 96, 0.3)',
  },
  logo: {
    fontSize: '28px',
    fontWeight: '700',
    color: '#e94560',
    textDecoration: 'none',
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
  },
  navLinks: {
    display: 'flex',
    gap: '30px',
  },
  navLink: {
    color: '#fff',
    textDecoration: 'none',
    fontSize: '16px',
    fontWeight: '500',
    transition: 'color 0.3s',
    padding: '8px 16px',
    borderRadius: '8px',
  },
  heroSection: {
    textAlign: 'center',
    padding: '60px 20px',
    background: 'linear-gradient(135deg, rgba(233, 69, 96, 0.1) 0%, rgba(22, 33, 62, 0.5) 100%)',
    borderRadius: '20px',
    marginBottom: '40px',
  },
  heroTitle: {
    fontSize: '48px',
    fontWeight: '700',
    marginBottom: '15px',
    background: 'linear-gradient(90deg, #e94560, #ff6b6b)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
  },
  heroSubtitle: {
    fontSize: '18px',
    color: '#a0a0a0',
    maxWidth: '600px',
    margin: '0 auto',
  },
  filterSection: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '15px',
    marginBottom: '30px',
    padding: '20px',
    background: 'rgba(255, 255, 255, 0.05)',
    borderRadius: '15px',
  },
  searchInput: {
    flex: '1',
    minWidth: '250px',
    padding: '12px 20px',
    borderRadius: '10px',
    border: '2px solid rgba(233, 69, 96, 0.3)',
    background: 'rgba(26, 26, 46, 0.8)',
    color: '#fff',
    fontSize: '16px',
    outline: 'none',
    transition: 'border-color 0.3s',
  },
  select: {
    padding: '12px 20px',
    borderRadius: '10px',
    border: '2px solid rgba(233, 69, 96, 0.3)',
    background: 'rgba(26, 26, 46, 0.8)',
    color: '#fff',
    fontSize: '16px',
    outline: 'none',
    cursor: 'pointer',
    minWidth: '150px',
  },
  moviesGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
    gap: '25px',
    padding: '20px 0',
  },
  movieCard: {
    background: 'rgba(255, 255, 255, 0.05)',
    borderRadius: '15px',
    overflow: 'hidden',
    transition: 'transform 0.3s, box-shadow 0.3s',
    cursor: 'pointer',
    border: '1px solid rgba(233, 69, 96, 0.2)',
  },
  movieImage: {
    width: '100%',
    height: '350px',
    objectFit: 'cover',
    background: 'linear-gradient(135deg, #2a2a4a 0%, #1a1a2e 100%)',
  },
  movieInfo: {
    padding: '20px',
  },
  movieTitle: {
    fontSize: '18px',
    fontWeight: '600',
    marginBottom: '8px',
    color: '#fff',
  },
  movieMeta: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '10px',
  },
  genreBadge: {
    background: 'linear-gradient(90deg, #e94560, #ff6b6b)',
    padding: '5px 12px',
    borderRadius: '20px',
    fontSize: '12px',
    fontWeight: '500',
  },
  rating: {
    display: 'flex',
    alignItems: 'center',
    gap: '5px',
    color: '#ffd700',
    fontWeight: '600',
  },
  detailPage: {
    padding: '40px 20px',
  },
  detailContainer: {
    display: 'grid',
    gridTemplateColumns: '400px 1fr',
    gap: '40px',
    background: 'rgba(255, 255, 255, 0.05)',
    borderRadius: '20px',
    overflow: 'hidden',
  },
  detailImage: {
    width: '100%',
    height: '100%',
    minHeight: '500px',
    objectFit: 'cover',
  },
  detailInfo: {
    padding: '40px 40px 40px 0',
  },
  detailTitle: {
    fontSize: '36px',
    fontWeight: '700',
    marginBottom: '20px',
  },
  detailMeta: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '15px',
    marginBottom: '25px',
  },
  metaItem: {
    background: 'rgba(233, 69, 96, 0.2)',
    padding: '8px 16px',
    borderRadius: '8px',
    fontSize: '14px',
  },
  description: {
    fontSize: '16px',
    lineHeight: '1.8',
    color: '#c0c0c0',
    marginBottom: '25px',
  },
  infoRow: {
    display: 'flex',
    gap: '10px',
    marginBottom: '15px',
    fontSize: '15px',
  },
  infoLabel: {
    color: '#a0a0a0',
    minWidth: '100px',
  },
  infoValue: {
    color: '#fff',
    fontWeight: '500',
  },
  adminContainer: {
    padding: '40px 20px',
  },
  adminHeader: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '30px',
  },
  adminTitle: {
    fontSize: '32px',
    fontWeight: '700',
  },
  addButton: {
    background: 'linear-gradient(90deg, #e94560, #ff6b6b)',
    color: '#fff',
    border: 'none',
    padding: '12px 25px',
    borderRadius: '10px',
    fontSize: '16px',
    fontWeight: '600',
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
    transition: 'transform 0.3s',
  },
  modal: {
    position: 'fixed',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    background: 'rgba(0, 0, 0, 0.8)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    zIndex: 1000,
    padding: '20px',
  },
  modalContent: {
    background: '#1a1a2e',
    borderRadius: '20px',
    padding: '30px',
    width: '100%',
    maxWidth: '600px',
    maxHeight: '90vh',
    overflowY: 'auto',
    border: '1px solid rgba(233, 69, 96, 0.3)',
  },
  modalTitle: {
    fontSize: '24px',
    fontWeight: '600',
    marginBottom: '25px',
    textAlign: 'center',
  },
  form: {
    display: 'flex',
    flexDirection: 'column',
    gap: '20px',
  },
  formGroup: {
    display: 'flex',
    flexDirection: 'column',
    gap: '8px',
  },
  label: {
    fontSize: '14px',
    fontWeight: '500',
    color: '#a0a0a0',
  },
  input: {
    padding: '12px 16px',
    borderRadius: '10px',
    border: '2px solid rgba(233, 69, 96, 0.3)',
    background: 'rgba(26, 26, 46, 0.8)',
    color: '#fff',
    fontSize: '16px',
    outline: 'none',
  },
  textarea: {
    padding: '12px 16px',
    borderRadius: '10px',
    border: '2px solid rgba(233, 69, 96, 0.3)',
    background: 'rgba(26, 26, 46, 0.8)',
    color: '#fff',
    fontSize: '16px',
    outline: 'none',
    minHeight: '120px',
    resize: 'vertical',
  },
  formRow: {
    display: 'grid',
    gridTemplateColumns: '1fr 1fr',
    gap: '15px',
  },
  buttonGroup: {
    display: 'flex',
    gap: '15px',
    marginTop: '10px',
  },
  submitButton: {
    flex: 1,
    background: 'linear-gradient(90deg, #e94560, #ff6b6b)',
    color: '#fff',
    border: 'none',
    padding: '14px',
    borderRadius: '10px',
    fontSize: '16px',
    fontWeight: '600',
    cursor: 'pointer',
  },
  cancelButton: {
    flex: 1,
    background: 'transparent',
    color: '#fff',
    border: '2px solid rgba(255, 255, 255, 0.3)',
    padding: '14px',
    borderRadius: '10px',
    fontSize: '16px',
    fontWeight: '600',
    cursor: 'pointer',
  },
  adminTable: {
    width: '100%',
    borderCollapse: 'collapse',
    background: 'rgba(255, 255, 255, 0.05)',
    borderRadius: '15px',
    overflow: 'hidden',
  },
  tableHeader: {
    background: 'rgba(233, 69, 96, 0.2)',
  },
  th: {
    padding: '15px 20px',
    textAlign: 'left',
    fontWeight: '600',
    fontSize: '14px',
    color: '#e94560',
  },
  td: {
    padding: '15px 20px',
    borderBottom: '1px solid rgba(255, 255, 255, 0.1)',
    fontSize: '14px',
  },
  tableImage: {
    width: '60px',
    height: '80px',
    objectFit: 'cover',
    borderRadius: '8px',
  },
  actionButton: {
    padding: '8px 15px',
    borderRadius: '6px',
    border: 'none',
    cursor: 'pointer',
    fontSize: '13px',
    fontWeight: '500',
    marginRight: '8px',
  },
  editButton: {
    background: '#3498db',
    color: '#fff',
  },
  deleteButton: {
    background: '#e74c3c',
    color: '#fff',
  },
  fileInput: {
    padding: '12px',
    borderRadius: '10px',
    border: '2px dashed rgba(233, 69, 96, 0.5)',
    background: 'rgba(26, 26, 46, 0.8)',
    color: '#fff',
    cursor: 'pointer',
  },
  previewImage: {
    width: '100%',
    maxHeight: '200px',
    objectFit: 'cover',
    borderRadius: '10px',
    marginTop: '10px',
  },
  backButton: {
    display: 'inline-flex',
    alignItems: 'center',
    gap: '8px',
    color: '#e94560',
    textDecoration: 'none',
    fontSize: '16px',
    marginBottom: '20px',
    fontWeight: '500',
  },
  recommendSection: {
    marginTop: '50px',
    paddingTop: '30px',
    borderTop: '1px solid rgba(255, 255, 255, 0.1)',
  },
  recommendTitle: {
    fontSize: '24px',
    fontWeight: '600',
    marginBottom: '20px',
  },
  emptyState: {
    textAlign: 'center',
    padding: '80px 20px',
    color: '#a0a0a0',
  },
  emptyIcon: {
    fontSize: '64px',
    marginBottom: '20px',
  },
};

// Navbar Component
function Navbar() {
  return (
    <nav style={styles.navbar}>
      <Link to="/" style={styles.logo}>
        🎬 MovieHub
      </Link>
      <div style={styles.navLinks}>
        <Link to="/" style={styles.navLink}>Home</Link>
        {/* <Link to="/admin" style={styles.navLink}>Admin</Link> */}
      </div>
    </nav>
  );
}

// Home Page Component
function HomePage() {
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [selectedGenre, setSelectedGenre] = useState('All');
  const [sortBy, setSortBy] = useState('latest');
  const navigate = useNavigate();

  useEffect(() => {
    fetchMovies();
  }, [selectedGenre, sortBy]);

  const fetchMovies = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (selectedGenre !== 'All') params.append('genre', selectedGenre);
      if (sortBy === 'rating') params.append('sort', 'rating');
      if (sortBy === 'year') params.append('sort', 'year');
      if (sortBy === 'title') params.append('sort', 'title');

      const response = await axios.get(`${API_URL}/movies?${params}`);
      setMovies(response.data);
    } catch (error) {
      toast.error('Failed to fetch movies');
    } finally {
      setLoading(false);
    }
  };

  const filteredMovies = movies.filter(movie =>
    movie.title.toLowerCase().includes(search.toLowerCase()) ||
    movie.director.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div style={styles.container}>
      <div style={styles.heroSection}>
        <h1 style={styles.heroTitle}>Discover Amazing Movies</h1>
        <p style={styles.heroSubtitle}>
          Explore our curated collection of movies across all genres. Find your next favorite film today!
        </p>
      </div>

      <div style={styles.filterSection}>
        <input
          type="text"
          placeholder="🔍 Search movies, directors..."
          style={styles.searchInput}
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
        <select
          style={styles.select}
          value={selectedGenre}
          onChange={(e) => setSelectedGenre(e.target.value)}
        >
          <option value="All">All Genres</option>
          {genres.map(genre => (
            <option key={genre} value={genre}>{genre}</option>
          ))}
        </select>
        <select
          style={styles.select}
          value={sortBy}
          onChange={(e) => setSortBy(e.target.value)}
        >
          <option value="latest">Latest First</option>
          <option value="rating">Highest Rated</option>
          <option value="year">Release Year</option>
          <option value="title">Title A-Z</option>
        </select>
      </div>

      {loading ? (
        <div style={styles.emptyState}>
          <div style={styles.emptyIcon}>⏳</div>
          <p>Loading movies...</p>
        </div>
      ) : filteredMovies.length === 0 ? (
        <div style={styles.emptyState}>
          <div style={styles.emptyIcon}>🎬</div>
          <p>No movies found. Check back later!</p>
        </div>
      ) : (
        <div style={styles.moviesGrid}>
          {filteredMovies.map(movie => (
            <div
              key={movie._id}
              style={styles.movieCard}
              onClick={() => navigate(`/movie/${movie._id}`)}
              onMouseEnter={(e) => {
                e.currentTarget.style.transform = 'translateY(-10px)';
                e.currentTarget.style.boxShadow = '0 20px 40px rgba(233, 69, 96, 0.3)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.boxShadow = 'none';
              }}
            >
              {movie.imageUrl ? (
                <img src={movie.imageUrl} alt={movie.title} style={styles.movieImage} />
              ) : (
                <div style={{ ...styles.movieImage, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '48px' }}>
                  🎬
                </div>
              )}
              <div style={styles.movieInfo}>
                <h3 style={styles.movieTitle}>{movie.title}</h3>
                <div style={styles.movieMeta}>
                  <span style={styles.genreBadge}>{movie.genre}</span>
                  <span style={styles.rating}>⭐ {movie.rating.toFixed(1)}</span>
                </div>
                <p style={{ color: '#a0a0a0', fontSize: '14px' }}>{movie.releaseYear} • {movie.duration} min</p>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// Movie Detail Page Component
function MovieDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [movie, setMovie] = useState(null);
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMovie();
  }, [id]);

  const fetchMovie = async () => {
    try {
      setLoading(true);
      const response = await axios.get(`${API_URL}/movies/${id}`);
      setMovie(response.data);
      
      // Fetch recommendations
      const recResponse = await axios.get(`${API_URL}/movies/recommend/${response.data.genre}`);
      setRecommendations(recResponse.data.filter(m => m._id !== id));
    } catch (error) {
      toast.error('Failed to fetch movie details');
      navigate('/');
    } finally {
      setLoading(false);
    }
  };

  if (loading || !movie) {
    return (
      <div style={styles.emptyState}>
        <div style={styles.emptyIcon}>⏳</div>
        <p>Loading movie details...</p>
      </div>
    );
  }

  return (
    <div style={styles.detailPage}>
      <Link to="/" style={styles.backButton}>← Back to Movies</Link>
      
      <div style={styles.detailContainer}>
        {movie.imageUrl ? (
          <img src={movie.imageUrl} alt={movie.title} style={styles.detailImage} />
        ) : (
          <div style={{ ...styles.detailImage, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '100px', background: 'linear-gradient(135deg, #2a2a4a 0%, #1a1a2e 100%)' }}>
            🎬
          </div>
        )}
        <div style={styles.detailInfo}>
          <h1 style={styles.detailTitle}>{movie.title}</h1>
          <div style={styles.detailMeta}>
            <span style={styles.genreBadge}>{movie.genre}</span>
            <span style={{ ...styles.metaItem, background: 'rgba(255, 215, 0, 0.2)' }}>⭐ {movie.rating.toFixed(1)}</span>
            <span style={styles.metaItem}>{movie.releaseYear}</span>
            <span style={styles.metaItem}>🕐 {movie.duration} min</span>
          </div>
          <p style={styles.description}>{movie.description}</p>
          <div style={styles.infoRow}>
            <span style={styles.infoLabel}>Director:</span>
            <span style={styles.infoValue}>{movie.director}</span>
          </div>
          <div style={styles.infoRow}>
            <span style={styles.infoLabel}>Cast:</span>
            <span style={styles.infoValue}>{movie.cast}</span>
          </div>
        </div>
      </div>

      {recommendations.length > 0 && (
        <div style={styles.recommendSection}>
          <h2 style={styles.recommendTitle}>More {movie.genre} Movies</h2>
          <div style={styles.moviesGrid}>
            {recommendations.slice(0, 4).map(rec => (
              <div
                key={rec._id}
                style={styles.movieCard}
                onClick={() => navigate(`/movie/${rec._id}`)}
                onMouseEnter={(e) => {
                  e.currentTarget.style.transform = 'translateY(-10px)';
                  e.currentTarget.style.boxShadow = '0 20px 40px rgba(233, 69, 96, 0.3)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = 'none';
                }}
              >
                {rec.imageUrl ? (
                  <img src={rec.imageUrl} alt={rec.title} style={styles.movieImage} />
                ) : (
                  <div style={{ ...styles.movieImage, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '48px' }}>
                    🎬
                  </div>
                )}
                <div style={styles.movieInfo}>
                  <h3 style={styles.movieTitle}>{rec.title}</h3>
                  <div style={styles.movieMeta}>
                    <span style={styles.genreBadge}>{rec.genre}</span>
                    <span style={styles.rating}>⭐ {rec.rating.toFixed(1)}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// Admin Page Component
function AdminPage() {
  const [movies, setMovies] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editingMovie, setEditingMovie] = useState(null);
  const [loading, setLoading] = useState(true);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    genre: 'Action',
    releaseYear: new Date().getFullYear(),
    rating: 0,
    director: '',
    cast: '',
    duration: 120,
  });
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState('');

  useEffect(() => {
    fetchMovies();
  }, []);

  const fetchMovies = async () => {
    try {
      setLoading(true);
      const response = await axios.get(`${API_URL}/movies`);
      setMovies(response.data);
    } catch (error) {
      toast.error('Failed to fetch movies');
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const resetForm = () => {
    setFormData({
      title: '',
      description: '',
      genre: 'Action',
      releaseYear: new Date().getFullYear(),
      rating: 0,
      director: '',
      cast: '',
      duration: 120,
    });
    setImageFile(null);
    setImagePreview('');
    setEditingMovie(null);
  };

  const openAddModal = () => {
    resetForm();
    setShowModal(true);
  };

  const openEditModal = (movie) => {
    setEditingMovie(movie);
    setFormData({
      title: movie.title,
      description: movie.description,
      genre: movie.genre,
      releaseYear: movie.releaseYear,
      rating: movie.rating,
      director: movie.director,
      cast: movie.cast,
      duration: movie.duration,
    });
    setImagePreview(movie.imageUrl || '');
    setShowModal(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    const data = new FormData();
    Object.keys(formData).forEach(key => {
      data.append(key, formData[key]);
    });
    if (imageFile) {
      data.append('image', imageFile);
    }

    try {
      if (editingMovie) {
        await axios.put(`${API_URL}/movies/${editingMovie._id}`, data, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Movie updated successfully!');
      } else {
        await axios.post(`${API_URL}/movies`, data, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Movie added successfully!');
      }
      setShowModal(false);
      resetForm();
      fetchMovies();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Operation failed');
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this movie?')) {
      try {
        await axios.delete(`${API_URL}/movies/${id}`);
        toast.success('Movie deleted successfully!');
        fetchMovies();
      } catch (error) {
        toast.error('Failed to delete movie');
      }
    }
  };

  return (
    <div style={styles.adminContainer}>
      <div style={styles.adminHeader}>
        <h1 style={styles.adminTitle}>🎬 Movie Management</h1>
        <button style={styles.addButton} onClick={openAddModal}>
          ➕ Add New Movie
        </button>
      </div>

      {loading ? (
        <div style={styles.emptyState}>
          <div style={styles.emptyIcon}>⏳</div>
          <p>Loading movies...</p>
        </div>
      ) : movies.length === 0 ? (
        <div style={styles.emptyState}>
          <div style={styles.emptyIcon}>📽️</div>
          <p>No movies yet. Add your first movie!</p>
        </div>
      ) : (
        <div style={{ overflowX: 'auto' }}>
          <table style={styles.adminTable}>
            <thead style={styles.tableHeader}>
              <tr>
                <th style={styles.th}>Image</th>
                <th style={styles.th}>Title</th>
                <th style={styles.th}>Genre</th>
                <th style={styles.th}>Year</th>
                <th style={styles.th}>Rating</th>
                <th style={styles.th}>Director</th>
                <th style={styles.th}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {movies.map(movie => (
                <tr key={movie._id}>
                  <td style={styles.td}>
                    {movie.imageUrl ? (
                      <img src={movie.imageUrl} alt={movie.title} style={styles.tableImage} />
                    ) : (
                      <div style={{ ...styles.tableImage, display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#2a2a4a' }}>
                        🎬
                      </div>
                    )}
                  </td>
                  <td style={styles.td}>{movie.title}</td>
                  <td style={styles.td}>
                    <span style={styles.genreBadge}>{movie.genre}</span>
                  </td>
                  <td style={styles.td}>{movie.releaseYear}</td>
                  <td style={styles.td}>⭐ {movie.rating.toFixed(1)}</td>
                  <td style={styles.td}>{movie.director}</td>
                  <td style={styles.td}>
                    <button
                      style={{ ...styles.actionButton, ...styles.editButton }}
                      onClick={() => openEditModal(movie)}
                    >
                      ✏️ Edit
                    </button>
                    <button
                      style={{ ...styles.actionButton, ...styles.deleteButton }}
                      onClick={() => handleDelete(movie._id)}
                    >
                      🗑️ Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {showModal && (
        <div style={styles.modal} onClick={() => setShowModal(false)}>
          <div style={styles.modalContent} onClick={e => e.stopPropagation()}>
            <h2 style={styles.modalTitle}>
              {editingMovie ? '✏️ Edit Movie' : '➕ Add New Movie'}
            </h2>
            <form style={styles.form} onSubmit={handleSubmit}>
              <div style={styles.formGroup}>
                <label style={styles.label}>Title *</label>
                <input
                  type="text"
                  name="title"
                  value={formData.title}
                  onChange={handleInputChange}
                  style={styles.input}
                  required
                  placeholder="Enter movie title"
                />
              </div>

              <div style={styles.formGroup}>
                <label style={styles.label}>Description *</label>
                <textarea
                  name="description"
                  value={formData.description}
                  onChange={handleInputChange}
                  style={styles.textarea}
                  required
                  placeholder="Enter movie description"
                />
              </div>

              <div style={styles.formRow}>
                <div style={styles.formGroup}>
                  <label style={styles.label}>Genre *</label>
                  <select
                    name="genre"
                    value={formData.genre}
                    onChange={handleInputChange}
                    style={styles.select}
                    required
                  >
                    {genres.map(genre => (
                      <option key={genre} value={genre}>{genre}</option>
                    ))}
                  </select>
                </div>
                <div style={styles.formGroup}>
                  <label style={styles.label}>Release Year *</label>
                  <input
                    type="number"
                    name="releaseYear"
                    value={formData.releaseYear}
                    onChange={handleInputChange}
                    style={styles.input}
                    required
                    min="1900"
                    max={new Date().getFullYear() + 5}
                  />
                </div>
              </div>

              <div style={styles.formRow}>
                <div style={styles.formGroup}>
                  <label style={styles.label}>Rating (0-10)</label>
                  <input
                    type="number"
                    name="rating"
                    value={formData.rating}
                    onChange={handleInputChange}
                    style={styles.input}
                    min="0"
                    max="10"
                    step="0.1"
                  />
                </div>
                <div style={styles.formGroup}>
                  <label style={styles.label}>Duration (minutes) *</label>
                  <input
                    type="number"
                    name="duration"
                    value={formData.duration}
                    onChange={handleInputChange}
                    style={styles.input}
                    required
                    min="1"
                  />
                </div>
              </div>

              <div style={styles.formGroup}>
                <label style={styles.label}>Director *</label>
                <input
                  type="text"
                  name="director"
                  value={formData.director}
                  onChange={handleInputChange}
                  style={styles.input}
                  required
                  placeholder="Enter director name"
                />
              </div>

              <div style={styles.formGroup}>
                <label style={styles.label}>Cast *</label>
                <input
                  type="text"
                  name="cast"
                  value={formData.cast}
                  onChange={handleInputChange}
                  style={styles.input}
                  required
                  placeholder="Enter main cast (comma separated)"
                />
              </div>

              <div style={styles.formGroup}>
                <label style={styles.label}>Movie Poster</label>
                <input
                  type="file"
                  accept="image/*"
                  onChange={handleImageChange}
                  style={styles.fileInput}
                />
                {imagePreview && (
                  <img src={imagePreview} alt="Preview" style={styles.previewImage} />
                )}
              </div>

              <div style={styles.buttonGroup}>
                <button type="button" style={styles.cancelButton} onClick={() => setShowModal(false)}>
                  Cancel
                </button>
                <button type="submit" style={styles.submitButton}>
                  {editingMovie ? 'Update Movie' : 'Add Movie'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

// Main App Component
function App() {
  return (
    <Router>
      <div>
        <Navbar />
        <Routes>
          <Route path="/" element={<HomePage />} />
          <Route path="/movie/:id" element={<MovieDetailPage />} />
          <Route path="/admin" element={<AdminPage />} />
        </Routes>
        <ToastContainer
          position="bottom-right"
          theme="dark"
          autoClose={3000}
        />
      </div>
    </Router>
  );
}

export default App;
